select count(*) from postgres.comments as c, postgres.posts as p, postgres.votes as v, postgres.users as u where u.id = p.owneruserid and u.id = c.userid and u.id = v.userid and p.score<=52 and p.answercount>=0 and v.creationdate>=timestamp '2010-07-20 00:00:00' and u.upvotes>=0 and u.creationdate>=timestamp '2010-10-05 05:52:35' and u.creationdate<=timestamp '2014-09-08 15:55:02';
